import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

export async function verifiedRagQuery(query: string) {
  const docs = await retriever.getRelevantDocuments(query);
  const context = docs.map(doc => doc.pageContent).join('\n');

  const result = await chain.call({ context, question: query });

  const verified = await vex.verify({
    input: { query, context },
    output: result.content,
    sources: docs.map(doc => doc.metadata),
    checks: ['source_faithfulness', 'context_relevance'],
    riskProfile: 'high'
  });

  if (!verified.passes) {
    throw new Error(`Verification failed: ${verified.issues.join(', ')}`);
  }

  return { ...result, verified: true };
}
